// MinimockFinishLoginInspect logs each unmet expectation
func (m *EngineMock) MinimockFinishLoginInspect() {
	for _, e := range m.FinishLoginMock.expectations {
		if mm_atomic.LoadUint64(&e.Counter) < 1 {
			m.t.Errorf("Expected call to EngineMock.FinishLogin at\n%s with params: %#v", e.expectationOrigins.origin, *e.params)
		}
	}

	afterFinishLoginCounter := mm_atomic.LoadUint64(&m.afterFinishLoginCounter)
	// if default expectation was set then invocations count should be greater than zero
	if m.FinishLoginMock.defaultExpectation != nil && afterFinishLoginCounter < 1 {
		if m.FinishLoginMock.defaultExpectation.params == nil {
			m.t.Errorf("Expected call to EngineMock.FinishLogin at\n%s", m.FinishLoginMock.defaultExpectation.returnOrigin)
		} else {
			m.t.Errorf("Expected call to EngineMock.FinishLogin at\n%s with params: %#v", m.FinishLoginMock.defaultExpectation.expectationOrigins.origin, *m.FinishLoginMock.defaultExpectation.params)
		}
	}
	// if func was set then invocations count should be greater than zero
	if m.funcFinishLogin != nil && afterFinishLoginCounter < 1 {
		m.t.Errorf("Expected call to EngineMock.FinishLogin at\n%s", m.funcFinishLoginOrigin)
	}

	if !m.FinishLoginMock.invocationsDone() && afterFinishLoginCounter > 0 {
		m.t.Errorf("Expected %d calls to EngineMock.FinishLogin at\n%s but found %d calls",
			mm_atomic.LoadUint64(&m.FinishLoginMock.expectedInvocations), m.FinishLoginMock.expectedInvocationsOrigin, afterFinishLoginCounter)
	}
}

